# chat-frontend/tests/pact/test_claude_pact_matchers.py
from pact import Consumer, Provider, Like, EachLike, Term

def test_chat_completion_with_matchers(pact):
    """
    Like() matches the type and structure, not the exact value.
    Term() matches a regex pattern.
    EachLike() requires at least one item matching the template.
    """
    (
        pact
        .given("the claude service is available")
        .upon_receiving("a chat completion with matchers")
        .with_request(
            method="POST",
            path="/v1/messages",
            body={
                "model": Like("claude-haiku-4-5-20251001"),
                "max_tokens": Like(256),
                "messages": EachLike(
                    {"role": Term("user|assistant", "user"), "content": Like("hello")}
                ),
            },
        )
        .will_respond_with(
            status=200,
            body={
                "content": EachLike({"type": "text", "text": Like("some response")}),
                "model": Like("claude-haiku-4-5-20251001"),
                "stop_reason": Term("end_turn|max_tokens", "end_turn"),
                "usage": {
                    "input_tokens": Like(10),
                    "output_tokens": Like(20),
                },
            },
        )
    )
    with pact:
        resp = requests.post(
            f"http://{PACT_HOST}:{PACT_PORT}/v1/messages",
            json={
                "model": "claude-haiku-4-5-20251001",
                "max_tokens": 256,
                "messages": [{"role": "user", "content": "hello"}],
            },
        )
        assert resp.status_code == 200
        body = resp.json()
        # Consumer only checks the fields it actually uses
        assert isinstance(body["content"], list)
        assert body["content"][0]["type"] == "text"

// pacts/chat-frontend-claude-service.json  (auto-generated — do not edit by hand)
